  ('social-worker-moex-08131', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '2002 年內政部兒童局訂定「受虐兒童家庭維繫及家庭重整服務實施計畫」。這是援引美國的家庭維繫方案 （Family Preservation）之概念，以協助受虐兒童家庭。以下敘述，那三種服務特質符合家庭維繫方案的實', '["減少兒童家外安置", "增加寄養服務", "提供密集性家庭服務", "增強原生家庭權能  ⑤增強 寄養家庭權能"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08132', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關家庭暴力婦女的服務，Dutton（1992）認為不論那一個專業領域，對受暴婦女的處遇有那三個基本目標？', '["轉介服務", "增強婚姻關係", "保護", "增強其權能與作決定  ⑤創傷復原"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
